import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import api from '../api';
import './Forms.css';

const BLOOD_GROUPS = ['A+', 'A-', 'B+', 'B-', 'AB+', 'AB-', 'O+', 'O-'];
const URGENCY_LEVELS = [
  { value: 'critical', label: '🔴 Critical', desc: 'Life-threatening, immediate need' },
  { value: 'high',     label: '🟠 High',     desc: 'Needed within hours' },
  { value: 'medium',   label: '🟡 Medium',   desc: 'Needed within a day' },
  { value: 'low',      label: '🟢 Low',      desc: 'Scheduled / non-urgent' },
];

export default function EmergencyRequest() {
  const { register, handleSubmit, formState: { errors } } = useForm();
  const navigate = useNavigate();
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [urgency, setUrgency] = useState('');

  const onSubmit = async (data) => {
    if (!urgency) { setError('Please select an urgency level'); return; }
    setError('');
    setLoading(true);
    try {
      const res = await api.post('/create-request', {
        ...data,
        urgency,
        units_needed: parseInt(data.units_needed, 10),
        latitude: data.latitude ? parseFloat(data.latitude) : null,
        longitude: data.longitude ? parseFloat(data.longitude) : null,
      });
      navigate(`/matched/${res.data.request.id}`);
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to create request.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="page-container">
      <h1 className="page-title">🚨 Emergency Blood Request</h1>

      <div className="form-card card">
        {error && <div className="alert alert-error">{error}</div>}

        <form onSubmit={handleSubmit(onSubmit)}>
          <div className="grid-2">
            <div className="form-group">
              <label>Patient Name *</label>
              <input placeholder="Full name of patient" {...register('patient_name', { required: 'Patient name is required' })} />
              {errors.patient_name && <span className="error">{errors.patient_name.message}</span>}
            </div>

            <div className="form-group">
              <label>Blood Group Required *</label>
              <select {...register('blood_group', { required: 'Blood group is required' })}>
                <option value="">Select blood group</option>
                {BLOOD_GROUPS.map(g => <option key={g} value={g}>{g}</option>)}
              </select>
              {errors.blood_group && <span className="error">{errors.blood_group.message}</span>}
            </div>

            <div className="form-group">
              <label>Units Needed *</label>
              <input type="number" min="1" max="20" placeholder="e.g. 2" {...register('units_needed', { required: 'Units needed is required', min: { value: 1, message: 'At least 1 unit' } })} />
              {errors.units_needed && <span className="error">{errors.units_needed.message}</span>}
            </div>

            <div className="form-group">
              <label>Contact Number *</label>
              <input placeholder="+1 555 000 0000" {...register('contact_number', { required: 'Contact number is required' })} />
              {errors.contact_number && <span className="error">{errors.contact_number.message}</span>}
            </div>

            <div className="form-group">
              <label>Hospital Name *</label>
              <input placeholder="e.g. City General Hospital" {...register('hospital_name', { required: 'Hospital name is required' })} />
              {errors.hospital_name && <span className="error">{errors.hospital_name.message}</span>}
            </div>

            <div className="form-group">
              <label>Location / City *</label>
              <input placeholder="e.g. New York, NY" {...register('location', { required: 'Location is required' })} />
              {errors.location && <span className="error">{errors.location.message}</span>}
            </div>

            <div className="form-group">
              <label>Latitude (optional)</label>
              <input type="number" step="any" placeholder="e.g. 40.7128" {...register('latitude')} />
            </div>
            <div className="form-group">
              <label>Longitude (optional)</label>
              <input type="number" step="any" placeholder="e.g. -74.0060" {...register('longitude')} />
            </div>
          </div>

          <div className="form-group">
            <label>Urgency Level *</label>
            <div className="urgency-grid">
              {URGENCY_LEVELS.map(u => (
                <button
                  key={u.value}
                  type="button"
                  className={`urgency-card ${urgency === u.value ? 'selected' : ''} urgency-${u.value}`}
                  onClick={() => setUrgency(u.value)}
                >
                  <span className="urgency-label">{u.label}</span>
                  <span className="urgency-desc">{u.desc}</span>
                </button>
              ))}
            </div>
          </div>

          <div className="form-actions">
            <button type="button" className="btn btn-secondary" onClick={() => navigate('/dashboard')}>Cancel</button>
            <button type="submit" className="btn btn-primary" disabled={loading}>
              {loading ? <><span className="spinner" /> Finding Donors...</> : '🚨 Submit Request & Find Donors'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
